# Apply
for subj_name, descs in [('pe', pe_descs), ('russian', russian_descs)]:
    path = os.path.join(grade_dir, f'{subj_name}.json')
    with open(path, 'r', encoding='utf-8') as f:
        data = json.load(f)
    
    idx = 0
    for dt in data['lessons']['detailedTopics']:
        for les in dt['lessons']:
            if idx < len(descs):
                les['description'] = descs[idx]
            idx += 1
    
    with open(path, 'w', encoding='utf-8') as f:
        json.dump(data, f, ensure_ascii=False, indent=2)
    
    # Verify
    min_desc = min(len(descs[i]) for i in range(min(idx, len(descs))))
    max_desc = max(len(descs[i]) for i in range(min(idx, len(descs))))
    print(f'{subj_name}: {idx} lessons, desc range {min_desc}-{max_desc}')

print('Done!')
